INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '喜欢的酒店，老牌风，有厚度。方便出行，出门右转即地铁站，去哪儿都很方便的。酒店的', '喜欢的酒店，老牌风，有厚度。方便出行，出门右转即地铁站，去哪儿都很方便的。酒店的餐厅好吃，服务也相当到位的。', '2024-07-02', 5, '[''交通便利性'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233f12000en9tv2dD349_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000en9vai5EFED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000en9jl2a0CE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000en9uvgfCFB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000en9miqdFFA0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000ena02ws4076_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000ena0ngsDD0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000ena1lmv4B06_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的热情，还送了鲜花，中文也说的非常好！儿子最近热衷看老王的视频，一个劲的说小哥好像老王。酒店荣誉满满，有自己的博物馆可以预约参观。下次到广州来还会选择！', '2024-04-05', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000dlert38C862_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000dlerrp0A264_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000dles3g6B491_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000dleqvsuB61A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000dlergu0B1AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000dles39v5755_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000dlerzfi490F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000dletad7DC66_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体可以，设施比较老一些', '总体可以，设施比较老一些', '2024-09-01', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234j12000fcd059r06FA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '真的是很用心在服务的酒店，装修很美，设施很棒。', '真的是很用心在服务的酒店，装修很美，设施很棒。
房间很舒服，宽敞干净', '2024-07-19', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000etuu1a9AA35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000etutd0m665D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000etv07mgA3D2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主动和我打招呼，入住认识了 前厅部副经理 Lavinia吴灵伶，很热情地给我办入住，让我感受到温暖和体贴的服务，非常满意，五星好评', '2024-08-08', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000f1uw0a8A2DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000f1v0u601BE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000f1uxsy0DB2F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000f1v0fky4712_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000f1v2hoa0F5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000f1utn7114DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000f1v0u624386_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转餐厅享用早餐，非常感谢！酒店就在地铁淘金站旁边，出行非常方便，距机场也只有二三十分钟车程。总之，本次广州之行让我爱上了广州。', '2024-04-05', 5, '[''整体满意度'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236w12000dlg1b9kEF0E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000dlg0iizB09E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000dlg0a8o359D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000dlg1b9m0EDB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000dlg004t2A0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000dlg0a8q495E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境优美，房间整洁，已多次入住，这次还免费升级房间??', '酒店环境优美，房间整洁，已多次入住，这次还免费升级房间??', '2024-07-27', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235i12000ex0sxz847F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000ex0rq7oB0C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000ex0s1l98CB1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '2024-07-20', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231r12000eub4wkq7E7F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000eub8q7j1DA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000euav5yt39CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000euay0i50DFE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000euav5yv169B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000euav5241261_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000eub8uudE6E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000eub0yljC261_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实本来冲着美食酒店入住的，对餐食有点小小的失望，不过下次来广州还会选择花园酒店。', '2024-04-28', 5, '[''前台服务'', ''整体满意度'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000dt5l3zjC8F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000dt5tntmAD54_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很不错，老牌五星级酒店标杆', '很不错，老牌五星级酒店标杆', '2024-08-28', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000fadl54sDC63_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '2024-07-24', 5, '[''卫生状况'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236612000evwes92537C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了一间套房，还附赠了行政酒廊入场券和早餐券；房间宽敞明亮整洁，硬件设施也无可挑剔；在暴雨天气下，酒店的娱乐设施（后花园博物馆什么的应有尽有）和餐饮也足够满足需求。凌璇阁的餐饮环境服务也让人印象深刻，特别是有一位印度裔的服务员Carrie很贴心，中文也特别好。Thank you Carrie！岭南集团的酒店水准一直都让人很满意！', '2024-04-28', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000dt9ldrn2326_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000dt8yqxq951B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000dt97mdzC449_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000dt9l6cx51F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000dt94xkhE35F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann和cassie直接帮忙升级为红棉房并加赠早餐以及酒廊待遇一人份；餐饮方面有多个餐厅可供选择，美食多样、服务勤快。总之，在携程活动加持下酒店体验超预期，大赞！', '2024-08-26', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000f9b4sgf72E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000f9b1tsb81A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000f9b5wswDA83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000f9b4mfb3A13_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老牌五星酒店，各类设施维护保养极好，服务更是保持了五星水准！强烈推荐！', '2024-04-13', 5, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236o12000do2nfbuC63F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000do2nwcwD440_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000do2of9v19D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000do2o1ymD7F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000do2on2b81A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000do2o0lr27C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000do2oc5aD319_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000do2p2c16A4E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000do2nfc311C4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞很多住起来很舒服，设施一点点旧但齐全整洁。客务中心小杨也有主动了解体验反馈。
花园酒店真的经典，比起普通酒店好玩，岭南文化满满，这次有时间参观了四楼博物馆。瀑布餐厅早餐时间开到11点，不用早起赶时间??餐厅view很好！24h的健身房也很贴心！下次来有机会再试试桃园馆餐厅！', '2025-04-06', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236012000jlptwfgE650_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000jlpsm9x9B8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000jlpeed1E1C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000jlq5jyaA7C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000jlpzmu6CAC5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '2024-07-30', 5, '[''餐饮设施'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0236v12000ey0mq9q18B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000ey0nqbmFFC7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000ey0idiyE835_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000ey0isywF9A9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000ey0grbgCCEA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童立马过来开门、提箱，引导到前台办理入住。客房干净整洁，就是隔音不是很好，酒店位置交通便利，出行方便。', '2024-04-14', 5, '[''前台服务'', ''交通便利性'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0201a12000doc614u8416_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0231z12000dobt8na5FEE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000doboa3gE46B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是白金五星，房间干净整洁，维护得很好。服务一流，大堂穿bulinhbulin', '不愧是白金五星，房间干净整洁，维护得很好。服务一流，大堂穿bulinhbuling衣服小姐姐太给力了。环境特别好，早餐丰富，地理位置也方便', '2024-05-16', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232d12000e0yhuatC48B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000e0yll022FD2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间安静舒适，整洁卫生，客务部小刘服务热情周到，客房服务员小王、Tina细心服务', '房间安静舒适，整洁卫生，客务部小刘服务热情周到，客房服务员小王、Tina细心服务??????', '2025-03-25', 5, '[''客房服务'', ''安静程度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000jb7pk2l058F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间舒适，环境很好，大堂小姐姐非常热情周到。交通便利，位置好。', '房间舒适，环境很好，大堂小姐姐非常热情周到。交通便利，位置好。', '2024-07-17', 5, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000et5lgs710C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000et5i632F2F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000et5lai952C8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这里非常舒适，环境也很漂亮。', '这里非常舒适，环境也很漂亮。
服务很周到。Viria很体贴', '2024-07-19', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236h12000ettoqnjD132_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000ettq38d396B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000ettuhhw0E75_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '终于有机会体验了一把心心念念的酒店，推门瞬间就有了度假的感觉。各方面服务都很贴心', '终于有机会体验了一把心心念念的酒店，推门瞬间就有了度假的感觉。各方面服务都很贴心，酒店套餐还可以再多一点～', '2024-07-23', 5, '[''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233k12000eva7ypv736B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000evabe9x211F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000eva6j3kE326_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000evaebm9B2CE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店花园很美，服务也很赞，真是一次美好的旅行', '酒店花园很美，服务也很赞，真是一次美好的旅行', '2024-08-01', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234g12000eynxv3n1D08_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000eynzfbc7D5C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000eyo92am510E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的花园酒廊堪称城市中的一方静谧绿洲，无论是环境、服务还是餐品都令人印', '广州花园酒店的花园酒廊堪称城市中的一方静谧绿洲，无论是环境、服务还是餐品都令人印象深刻。步入酒廊的瞬间，便被其优雅的设计所吸引——挑高的玻璃穹顶将自然光线温柔洒落，绿植环绕的空间与典雅的欧式家具相映成趣，仿佛置身都市花园。落地窗外是郁郁葱葱的庭院景观，尤其在午后阳光斜照时，光影交错间更显诗意，随手一拍皆是质感大片。
服务细节堪称典范，花园酒廊的Kitty小姐姐笑容亲切且专业高效，从入座时的贴心指引到点单时的细致推荐，无不体现白金五星级酒店的待客之道。席间Kitty会主动询问需求，甚至为我们拍照调整灯光角度，细微之处尽显用心。
餐品方面，花园酒廊的欢乐时光堪称招牌。三层银质托盘上，咸甜搭配的精致点心既满足味蕾又充满艺术感——烟熏三文鱼挞的咸香、芒果慕斯的清甜、司康饼的松软温热，每一口都令人回味。特调饮品也别具巧思，推荐尝试以岭南水果为灵感的季节限定鸡尾酒，果香与酒香融合得恰到好处。若赶上晚上，现场还会有乐队演奏，无论家庭小聚、商务洽谈或独自放空都极为适宜。
总体而言，花园酒廊以高品质的环境与服务，将都市奢华与自然惬意完美结合，是值得反复打卡的城中秘境。离店时还会送酒店特色小羊，这份温暖的小惊喜，为我的出行体验画上了圆满句号。', '2025-03-13', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235m12000j1u17lk326B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000j1u2gqd6C6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000j1u2epf5041_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000j1u1b6e7717_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000j1ujdzn4281_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州老牌五星，名不虚传。管理到位，服务员认真客气，业务能力强，酒店整个环境非常好', '广州老牌五星，名不虚传。管理到位，服务员认真客气，业务能力强，酒店整个环境非常好，有自己的后花园，餐饮档次高，早餐很认真。周边出行也方便，对面友谊商店六楼的广州酒店品质很高。这次酒店很客气，还给我们升级了套房，很棒。以往升级最多是亲子房湖景房或者海景房，第一次碰到五星级能升级套房的。感谢酒店的精心服务！', '2024-03-23', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000dhh5oia214B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000dhh5jgj908E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000dhh5gbgE843_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000dhh5dpl9591_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000dhh568u8C42_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000dhh5y1l3C86_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感觉依旧很不错', '感觉依旧很不错', '2024-09-04', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000fe4q24t7F29_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常棒的老牌酒店，服务也很好', '非常棒的老牌酒店，服务也很好', '2024-09-10', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234q12000fhpfa7h8DCB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：作为中国白金级别酒店所有设施一应俱全，甚至还有一个花园酒店博物馆??', '设施：作为中国白金级别酒店所有设施一应俱全，甚至还有一个花园酒店博物馆??

卫生：非常干净卫生，房间内的浴缸是我见过最干净的

环境：位于老城区黄金位置，出行交通都十分便利，是出游广州一个非常好的选择

服务：大大的好，从入住开始就感受到了服务的热情，因为我们提前有说过今天是家人生日，前台的VIRIA非常热情告知我生日的安排，不止升级了房型，还准备了蛋糕。客务部的小华还非常热心帮我们把蛋糕准备到了晚上才给我们，让我们享受到了最美味的蛋糕。临走的时候也和大堂的阿金表达了这次入住的感受，只能说非常满意！下次还要再来????', '2025-03-31', 5, '[''前台服务'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000jg1lqbaE7D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000jg0wveb5ED6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000jg1bqfqAF99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000jg0g7nz9727_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000jg0wjpzA8E9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次去广州都会选择入住花园，房间舒适干净，服务态度也很棒～这次朋友过来也推荐了她', '每次去广州都会选择入住花园，房间舒适干净，服务态度也很棒～这次朋友过来也推荐了她～位置优越出行方便！', '2024-06-06', 5, '[''整体满意度'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000echw4esBFF1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000ecicgnb20FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000eci7mkoBB7B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不错的酒店，地段很好，入住方便快捷，大堂漂亮，后面小花园风景也很美，因为有事只入', '不错的酒店，地段很好，入住方便快捷，大堂漂亮，后面小花园风景也很美，因为有事只入住一天，下次来广州继续选择该酒店。', '2024-05-21', 5, '[''交通便利性'', ''整体满意度'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0234u12000e3iitlo1AEC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000e3ijb2017BC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间卫生不错，酒店环境好，出入方便，这次前台服务感觉不怎地，有点感觉被套路了，我', '房间卫生不错，酒店环境好，出入方便，这次前台服务感觉不怎地，有点感觉被套路了，我们到酒店的时候差不多中午十一点多了，说我订的房间还没有打扫卫生，大概还需要一个多小时，接下来前台服务员说只有升级版的房间还有，另外还需加钱，大中午的我们只有升级了，心里有种说不出的感觉。', '2024-03-19', 5, '[''前台服务'', ''退房/入住效率'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236y12000dg7gf6hE5A4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常愉悦的入住体验，设施、服务、餐饮都特别完美。', '非常愉悦的入住体验，设施、服务、餐饮都特别完美。', '2024-07-24', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000evsf6sk009B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '顶级商圈，繁华街区，极佳的位置和国际化商业氛围。园景很特别，街景很活力。', '顶级商圈，繁华街区，极佳的位置和国际化商业氛围。园景很特别，街景很活力。', '2024-07-02', 5, '[''周边配套'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000enhpdq9064A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000enhc05u955D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000enhpyvo1B20_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务很好，很多外宾客人，出门就是地铁站，去哪里都很方面，非常推荐！', '酒店服务很好，很多外宾客人，出门就是地铁站，去哪里都很方面，非常推荐！', '2024-07-04', 5, '[''交通便利性'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000eoaq1kp6082_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '满意干净舒适', '满意干净舒适', '2024-09-01', 5, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000fccqokb765A_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这家广州地标酒店，依旧被惊艳得说不出话！踏入挑高10米的鎏金大堂瞬间，金龙藻井与', '这家广州地标酒店，依旧被惊艳得说不出话！踏入挑高10米的鎏金大堂瞬间，金龙藻井与巨型壁画交相辉映，随手一拍都是大片既视感。这次入住的虽有些瑕疵，但细节和卫生做到极致：浴巾蓬松度堪比云朵，迷你吧饮品排列如仪仗队般整齐，其他地方都一尘不染！
真正让体验升华的是充满温度的服务——前台的高效，礼宾部拉门小哥的欢迎；最令人印象深刻的是大堂经理小郑，热情与敏捷应对，必须大大的点赞！ 虽然酒店确实有历史，但如果说硬件是酒店的骨骼，服务便是流淌的血液。广州花园酒店用实力证明：真正的顶奢，永远以人为尺。  这次还遇到了超棒的前台VIRIA 。', '2025-03-25', 4, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234j12000jbekvhmD79A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000jbex529FAA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000jbek8apDB12_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店 一直喜欢 尤其喜欢酒店大堂和各个区域的鲜花摆设 别具一格 独显花城气质', '老牌酒店 一直喜欢 尤其喜欢酒店大堂和各个区域的鲜花摆设 别具一格 独显花城气质 这次有点时间 去逛了逛花园 岭南风格 绿植茂盛 锦鲤多多 酒店餐厅特别棒 每次都会特地去品尝广州美食 有水准 前台Rain 服务贴心 到位 及时解决问题 五星好评 推荐推荐', '2025-02-27', 4, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233w12000irrq5bmFED0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000irrqnh1F492_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000irrokri2B76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000irrpsbvC0EF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000irrjmj384A9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，一如既往如此优秀的酒店！超赞！', '花园酒店，一如既往如此优秀的酒店！超赞！', '2024-07-26', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000ewnwxf8BFCE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000ewnyudtA75B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000ewnww8hD3D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000ewnywf16E53_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带娃来广州玩选择了花园酒店，环境很棒，餐食都很好吃，服务特别好，尤其对小朋友真是', '带娃来广州玩选择了花园酒店，环境很棒，餐食都很好吃，服务特别好，尤其对小朋友真是太友好了，让妈妈们感受到满满的温暖', '2024-04-24', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236v12000drlwr0eF3B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000drlu9g2AFCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000drlu9g4537F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000drlu9wfF921_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000drlu9g63324_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000drlulnr3A2B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000drlu9wk3AE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000drlu9wmF906_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000drlu9ga77C5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节前带着父母孩子逛羊城入住了白金五星级的花园酒店，酒店1985年开业至今，除了', '春节前带着父母孩子逛羊城入住了白金五星级的花园酒店，酒店1985年开业至今，除了客房等正常损耗翻新外，基本上各种格局和摆设均保持了40年；在瀑布餐厅吃了早餐，荔湾厅吃了晚餐，味道也很好；入住的红棉房型，孩子高兴的手舞足蹈；在今日当值Golden Key John导览下参观了各个点，40年的酒店历史积淀深厚，父母平时比较少拍照的，没想到这次却是各种拍，直接停不下来，一改平时住酒店的风格；最后让我大感意外的是内设的博物馆，不仅可以对公众开放，还非常系统梳理了国内外酒店发展史，脉络非常清晰易懂，印象深刻，还有828间房体量的酒店，服务人员各种到位，无论餐厅，前台，接线员，真的是好的服务才让人更愿意再来。酒店位置也无敌，出门地铁站，西有越秀公园，东有动物园，无论带老人还是开孩子，可以说是游刃有余，无愧酒店标杆称号！下次来广州，还会住这里！', '2024-01-31', 5, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0235012000d3bu9iq51F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000d3bfu23D32A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000d3bjm5g0A66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000d3bm036F98C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000d3bw7xvD80B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000d3by8aiA6D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000d3by4fbAA8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000d3bg27fA45A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000d3bw17bDCC0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境人文都很不错，就是住的楼层高的话窗户是封闭的，其他都很好', '环境人文都很不错，就是住的楼层高的话窗户是封闭的，其他都很好', '2024-07-06', 5, '[''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000ep9jm3dE4B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000ep9gosg1B4B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000ep9ajb81B28_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '本来以为老牌酒店一切设施都比较老，实际上一进去就被金碧辉煌的大厅吸引了，然后酒店', '本来以为老牌酒店一切设施都比较老，实际上一进去就被金碧辉煌的大厅吸引了，然后酒店也很有复古风格，装饰的一些小细节都很棒。

然后大堂服务人员都很不错，有礼貌而且会有专门的服务员摁电梯。感谢大堂rebecca，给了我们一个不错的房间，而且相关情况讲解的都很清楚。

酒店位置也很不错，在老城区，旁边广州酒家、利苑和点都德这些走走就到，所以我们没有定早餐，早上直接去喝早茶非常方便。然后酒店自带的荔湾亭也很好吃啊，走的那天下雨，就没有出去觅食，去荔湾亭吃了一顿，云吞面和牛肉丸超赞。

总之是一个很不错的酒店，下次来广州还会入住，推荐给大家。', '2024-03-14', 5, '[''整体满意度'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234n12000devx9vfFFC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000devwxzl0F66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000dew70af16D6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意，客户服务非常到位！！感谢客房小赵的细心服务！！', '非常满意，客户服务非常到位！！感谢客房小赵的细心服务！！', '2024-10-15', 5, '[''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000g58q719E348_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很棒 前台小姐姐Pebecca给升了房间 特别喜欢 和朋友一起过生日 套房很', '房间很棒 前台小姐姐Pebecca给升了房间 特别喜欢 和朋友一起过生日 套房很大很干净 行政走廊风景优美 Ken的服务超级棒', '2024-04-30', 5, '[''房间设施'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000du0vhf0359D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000du0wicr101C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们此次预订了红棉大床房，房间面积很大，特别是入口客厅处的玻璃写字台，各种电器插', '我们此次预订了红棉大床房，房间面积很大，特别是入口客厅处的玻璃写字台，各种电器插口俱全，特别适合笔记本电脑办公。房间内设施豪华，十分养眼。此外，酒店距离地铁5号线淘金站很近，去哪里都方便，因而吸引了很多境外游客入住。我们从位于3楼的酒店博物馆得知，酒店大堂醒目处“花园酒店”四个大字，乃是小平同志亲笔题词。', '2024-03-09', 5, '[''房间设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233j12000ddiz0mh782B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境一流，鲜花环绕，名副其实的鲜花酒店。前台帮我们安排了朝向很好的户型，透过窗户', '环境一流，鲜花环绕，名副其实的鲜花酒店。前台帮我们安排了朝向很好的户型，透过窗户看园景，三月的羊城木棉花开，草坪上的喷泉潺潺，春意盎然的景象尽收眼底……
房间布局合理，洗浴分开很fashion，每日提供纯净水、胶囊咖啡和高档茶包，处处彰显五星级的周到、细致。
客服阿姨的服务一流，每天外出回来后房间里收拾得整整齐齐，干净清爽，衣服都帮我们折好。酒店打车非常方便，服务生会积极主动帮助拿行李，很贴心。
本次入住四天三晚，感受非常棒，下次还来！羊城首选！', '2024-03-10', 5, '[''景观/朝向'', ''客房服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232m12000ddp39tg970C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000ddp50w2AFD8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000ddox3i99D20_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000ddp886u700B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000ddp1xld3B44_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000ddp1229289E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000ddoqztd91AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000ddouequ2DE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000ddouh9t37F0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这回在广州过年，选择颇具特色的花园酒店。因行程有变，先订了两晚后又加了大年三十儿', '这回在广州过年，选择颇具特色的花园酒店。因行程有变，先订了两晚后又加了大年三十儿一晚，之前是花园双床房，最后一晚是城央绿意客房，因为过年，房价陡增，其实房型没有区别，房间面积较小，洗手台比较局促。有条件的话还是选面积更大的客房会舒服些。
其他都很满意。具体的在另一条评价里写了。', '2024-02-24', 5, '[''房间设施'', ''价格合理性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000da692wf9B96_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000da672hlD4E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000da6b0dd9BEE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000da648w92312_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000da6e3o7B5C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000da6a3ybD52A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000da6540s974E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000da6cyal7AA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000da63oyxBFD7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '最近几个月住的最好的酒店，没有之一！??环境好、服务好，房间干净宽敞！前台小哥哥', '最近几个月住的最好的酒店，没有之一！??环境好、服务好，房间干净宽敞！前台小哥哥看见我们带着两个小孩子还给免费升了房！优秀！酒店里的餐厅也超级棒！孩子很喜欢！', '2024-04-08', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000dmeitk3C55F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：花园酒店并非浪得虚名，后花园很漂亮。鱼池的卫生也维护得很好，没有垃圾漂浮物', '环境：花园酒店并非浪得虚名，后花园很漂亮。鱼池的卫生也维护得很好，没有垃圾漂浮物没有人喂鱼食。
服务：所有工作人员都很有礼貌
设施：需要提高亲子酒店的服务，毕竟现在很多家庭都是带着小朋友出行的。', '2024-02-12', 5, '[''公共设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235012000d6p7b59148E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000d6oyroxC2B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000d6oxasd3C3D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000d6ozmxc7E92_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000d6oupf30F5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000d6p9bm97B3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000d6p8o4zD245_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000d6oxasl3C63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000d6ohhrzD5D1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务超好，前台小哥哥非常nice，房间很舒服，有很多service，很干净，每次', '服务超好，前台小哥哥非常nice，房间很舒服，有很多service，很干净，每次来广州都住这里！！广州最好的酒店～酒店真的什么都有！', '2024-04-29', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236r12000dtn0bst3218_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000dtmx0lj3F7A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常舒适的一次住宿！感谢前台zara小姐姐，给我们安排了一个舒适的房间，全程接待', '非常舒适的一次住宿！感谢前台zara小姐姐，给我们安排了一个舒适的房间，全程接待效率快安排好。酒店风景好漂亮，下次还会来', '2024-11-07', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0234v12000gjtsub166D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000gjvxt0cB585_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000gjw2uze90CE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务不错，酒店环境不错，各色绣球花不错', '服务不错，酒店环境不错，各色绣球花不错', '2024-07-19', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000etshwn2CCDA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但各方面一点都不落后，设施绝对一流，服务十分到位，不愧为白金五星。
酒店周边配套很成熟，出行也很方便，出门就是地铁口，到市内多个景区也就半小时车程，周末过来citywalk感觉挺好的。退房后前台可以寄存行李，下午可以继续逛吃。
总之是一次满意的入住体验。', '2024-03-03', 5, '[''整体满意度'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000dc4u4ua3FC4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000dc4rcz222D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000dc4p6885F4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000dc4s5hu24BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000dc4uz5vAEA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000dc4ljegC633_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布餐厅，岭南花园，各种餐厅，小黄鸭是超大套房，还有一座宝藏的博物馆。服务水平高，总之就是让客人觉得舒适又体面。', '2024-02-19', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236412000d8pjfnqC231_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000d8pb3pn32B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000d8pdopmC1D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000d8pkbvpE206_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d8p96peA1A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000d8pa0tt1DAB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000d8p93et78AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236t12000d8pky90D9D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d8pczq70AF2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店从设施，装修风格及配置都非常高品质。服务员也很敬业，Gillian 给了我宾', '酒店从设施，装修风格及配置都非常高品质。服务员也很敬业，Gillian 给了我宾至如归的感觉。', '2024-05-21', 5, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000e3ij7aq381B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂豪华大气，迎宾员热情周到，房间整洁、干净、卫生，配套设施齐全，服务态度很', '酒店大堂豪华大气，迎宾员热情周到，房间整洁、干净、卫生，配套设施齐全，服务态度很好，酒店赠送的欢迎点心很漂亮，口感也很好，很满意。', '2024-04-21', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k12000dqrgt4gB09F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000dqqway17857_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000dqr77bjEEBC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000dqr3yzlAA86_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间装修很好，整洁，空气清新。', '房间装修很好，整洁，空气清新。
酒店大堂豪华大气，很多旅客在大堂拍照留念，我们也不例外。
酒店门口有循环车道，方便接送客户。还设有临时停车场，充电桩，规划得很周到。
花园酒店的五星级实至名归，快来体验吧！', '2024-03-03', 5, '[''房间设施'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230j12000dbytjd47062_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000dbyutin3A83_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境优美，服务热情，卫生干净，房间设施还行。', '环境优美，服务热情，卫生干净，房间设施还行。', '2024-07-09', 5, '[''整体满意度'', ''卫生状况'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236e12000eqb02d07362_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000eqbbfz19DC9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000eqb4sws0DA6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这个鲜花控。
健身室器材很多，保养得也不错，不逊正规健身房了。桑拿房干湿都有，唯一的缺点是没有冰毛巾。露天游泳池挺大，遗憾的是冬天没有开放。
行政走廊服务不错，但是空间比较小，餐食比较少，跟文华比差得不是一星半点。下午茶时间有红酒，可以小酌红酒一杯。欢乐时间的餐点都是冷盘，建议可以增加一两款热汤食，例如云吞面或者牛腩粉这种有广州特色的粉面，即能让外宾尝试广州美食也能满足中国胃。
入住的是基本房间，空间比较小也能理解，没有浴缸。
生日有小布置，还送了好吃的山楂蛋糕，加分。
有个酒店博物馆可以参观，可以了解一下酒店发展史，不错。
老牌五星酒店，外宾比较多。', '2024-01-28', 5, '[''公共设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233c12000d2btjcb34A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000d2bstwa2A82_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000d2bowki3948_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000d2bi3brED90_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000d2bu7gmD383_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000d2bnzrbA60E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000d2bh4qw3F78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000d2bhkbjB8DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000d2bjfeg338F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '2024-06-28', 5, '[''卫生状况'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234p12000elmw6sh899A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000elmxxg760C2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：房间里面偏旧，员工衣服太老土了，还不合身，皱皱巴巴', '设施：房间里面偏旧，员工衣服太老土了，还不合身，皱皱巴巴
卫生：一般，但是送了一份欢迎水果，不过不打招呼就私自放进房间有点吓人
环境：后面小花园蛮美的，但是不住也能去看，大厅也不错，就是感觉很乱
服务：还可以，主动帮忙拍照
总体而言，老式酒店，进去看看就行，特意住是真没必要', '2024-02-26', 4, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000dal3tpu776D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000dal6zg6DE0B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000dalism10421_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜之旅。酒店的环境、服务以及餐饮都让我们深感满意，让我们在南方的春节中，尽享了浓厚的年味。
广州花园酒店为我们提供了舒适的住宿环境，无论是房间的清洁度还是设施的完备性，都让我们倍感满意。在餐饮方面，酒店的年夜饭更是让人回味无穷，每一道菜品都充满了南方独特的年味，让我们一家人在除夕夜品尝到了家的味道。同时，酒店的卫生和服务也是无可挑剔的，让人感受到了一份温馨和关怀。
此次广州之旅，让我们充分领略了南方春节的独特魅力。酒店为我们呈现了一场别开生面的年味盛宴，让我们一家人在欢乐和温馨中度过了一个难忘的除夕之夜。
广州花园酒店无疑是一家高品质的酒店，无论是从硬件设施还是从服务细节上，都展现了其专业和贴心的水准。我们在此次旅行中收获了满满的愉快体验，我们愿意向更多的朋友推荐广州花园酒店，也期待未来再次来到这里。', '2024-02-12', 5, '[''整体满意度'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0200x12000d6rynjnC3CE_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0232f12000d6rpim0170D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000d6rtu207DEA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000d6rvhf20080_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000d6rmz7n79B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000d6rm1fg6F2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000d6rwcwm1BC8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000d6rhk91B994_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000d6rwsud7F52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000d6rbda38B5E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第三次来广州，果断选择花园酒店，免费升级了房间，非常感谢，前台服务态度也很好，非', '第三次来广州，果断选择花园酒店，免费升级了房间，非常感谢，前台服务态度也很好，非常满意的入住体验，下次来还会选择花园酒店', '2024-04-22', 4, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232312000dqu63vn5EF6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000dqu8c2uC194_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000dquc2i24C7C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生：不错', '卫生：不错
环境：不错
服务：不错
都不错就是房间稍微小了一点而已', '2024-06-08', 4, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232812000eduib0r1EBF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000educvvrE788_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000educ1fk1874_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000edu98c2F388_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置很好 出门就是地铁', '地理位置很好 出门就是地铁', '2024-09-22', 5, '[''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000fox84nnB267_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '五星级酒店，满意服务', '五星级酒店，满意服务', '2024-08-15', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233312000f4vsojv4827_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000f4vs3elBD3A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000f4vtygn0142_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想到的都有。大厅前台工作人员很多，主动帮拿行李，主动帮叫电梯，还有很多外籍服务人员，很国际化的老牌五星酒店。我这间房早餐是在30层旋转餐厅用餐，360度无死角边赏美景边用餐。ps：早餐炒菜类调整一俩道中式热炒会更好！', '2024-02-25', 5, '[''交通便利性'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234o12000dacfajoF531_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000dacf5pyE05B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000dacghh445A6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间咖啡机也是坏的，有些失望。走的时候原本想参观酒店博物馆，谁知星期一闭馆，又是遗憾。', '2024-04-10', 3, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000dmzdkvlBAFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000dmzvduh4CE5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000dmzvjc0A43F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000dmzl9euDBFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000dmzcxz17FBF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000dmzq8sw7CD9_R_150_150_R5_Q70_D.webp\", \"https://dimg04.c-ctrip.com/images/0231u12000dmzu9s1F119_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000dmzpf7e3D58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000dmzq556EFC7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场，但私人车位居多。房间景观：有多种客房、套房可供选择：粤韵客房、花园客房、岭南套房等，丰俭由人。餐厅：有9间餐厅可供就餐，中西法日各式菜系，还有酒吧咖啡厅等不同休闲应酬场所，适合各种人士的需求。服务：酒店大堂服务非常认真细致，主动打招呼、帮推门拿行李，外语交流流利。餐厅服务员热气好客，随传随到，斟茶收盘及时。其他：户外有个几层楼高的景观瀑布，在瀑布餐厅就餐可以一览无余：后门出口有网球场：写字楼区1-3楼有日本驻广州总领馆。室内除了餐厅外，还有多家时装服饰和艺术品商铺，3楼有9间多功能会议室和1个国际会议中心，经常举办大型国际性商务会议；4楼还有花园酒店博物馆，扫码实名登记可以进馆参观，馆内收藏有酒店故事和发展变迁的珍贵照片藏品，丰富了花园酒店的内涵。
行政走廊的Kanchan,Cathy,Beryle,前台服务人员kasas,betty温和有礼，热情招待', '2024-08-20', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000f6qbug5F26C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000f6qbt3pAD4D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000f6qa31gA328_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000f6qbyk09726_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000f6qggbs8A71_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000f6q8q23505F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000f6pmp18330A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000f6qdlv47601_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000f6qc6zn96BA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项目就是去小花园喂鱼，推荐入住', '2024-04-30', 5, '[''卫生状况'', ''安静程度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000du2be8iC0F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000du27zylE9FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000du2xvbz59E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000du2iny55522_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '槽点略多的酒店。', '槽点略多的酒店。
1. 携程上显示金卡可以升级房型，办理入住时表示要视当日房量而定，能理解，但我查看平台发现更高级的房型全都没有售空，希望前台再争取一下。前台女生走到旁边和另一个男生沟通，还没把我的诉求说完那个男生就立马说不行。当拒则拒，非常喜欢这种干脆果断的男生。
2. 房间明显有做翻修，但是翻修后的保养依然不太好。沙发套、办公椅等属于深度保洁的部分应该是没有常做的。浴缸有灰有毛发，日常保洁也欠佳。同时玻璃通透度太好了，不拉窗帘晚上恐有艳照门风险。
3. 外卖柜的位置令人感到匪夷所思。大堂设计本来就欠妥当，各种意义不明的隔断让人眼花缭乱，外卖柜更是设置在大堂深处角落。两个外卖柜不在一起不说，其中一个还设置在店铺里，标示牌也不明确。外卖员从正门进入酒店后要穿过整个大堂越过住客电梯厅才能到达外卖柜，所以大堂里乱哄哄的。这也是我第一次外卖送达取餐柜后被其他住客误取（这一点不完全是酒店责任，但也不能说完全和酒店无关。）
4. 外籍工作人员在入住期间打我手机求好评。相当不能理解，因为是外国人所以中文说得很艰难，考虑到他工作的辛苦我还是努力和他沟通希望听懂他的意思，但最后还是艰难地失败了，因为我听不懂他的名字。希望酒店可以让中外籍工作人员各管各的吧，是不愿意招中国人吗？
5. 花园瀑布挺漂亮的，但是晚上也开得太晚了，窗户隔音不好，明媚晴朗的夜晚听上去外面像在下暴雨。
整体看下来，酒店整体运营应该是遇到了一些问题，品控相当一般。
除去缺点以外，其他各方面表现（床品、个护用品、房间大小、地理位置等）也仅仅是尚可，和做得较好的连锁酒店是差不多的。表现最优秀的是餐饮，但是广州五星级酒店餐饮大多不差，甚至还有很出色的，故而也没有什么竞争力。', '2024-02-21', 2, '[''客房服务'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000d9ilv7fF4F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000d9itm2v2A42_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000d9j29511515_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000d9j1muh8B27_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂一进去很是惊艳，金碧辉煌，迎宾小妹的衣服更是金光闪闪，印象深刻。因为是老酒店', '大堂一进去很是惊艳，金碧辉煌，迎宾小妹的衣服更是金光闪闪，印象深刻。因为是老酒店改造，房间大小适中，不过陈设新颖。这里的服务员好多是外国人，还见到一些国外空乘人员。二楼的荔湾餐厅味道和风格都很独特正宗，连吃了两顿，省却了觅食的舟车劳顿，很加分。外出北京路步行街很方便，去机场也不远。', '2024-02-18', 5, '[''周边配套'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000d8hj7oq4673_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000d8heouzC7E1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务给的三星：', '服务给的三星：
客房服务很好，特别是2月17日晚上帮2510房间测试Wi-Fi连接的阿姨和技术部门男士，以及18日上午整理房间的小帅哥。
对比去年年前入住的体验，礼宾和前台有明显的疲惫感和生无可恋脸，人手也比去年少。估计是春节客流高峰所致。三星评价由此而来。

酒店位置很好，地铁打车公交都很方便。
设施维护很好。卫生很好。
红棉房据说是23年重新装修过，很新，房间一切都满意，就是2510房经测试没有Wi-Fi信号，希望酒店稍后调整，不再影响后面的住客。
早餐就中规中矩，倒是吃到了久违的烟熏三文鱼。好像疫情三年很多酒店都把这道取消了？（个人理解和经历）', '2024-02-20', 4, '[''客房服务'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236612000d97swjs3988_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000d97thxwC80F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000d97t62v109E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000d97tyi76995_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000d97swjuD352_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间温馨雅致，床垫软熟柔软，睡的很好.行政走廊Lina小姐姐服务很好，很温柔。', '房间温馨雅致，床垫软熟柔软，睡的很好.行政走廊Lina小姐姐服务很好，很温柔。', '2024-05-25', 5, '[''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000e5qnrzzC22C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店帮我们?升级了房型 很喜欢性价比很高', '酒店帮我们?升级了房型 很喜欢性价比很高', '2024-09-22', 5, '[''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231h12000fout4g55308_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000fouq4nwD9C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000foug1xb7B40_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒店，但处处体现的人文让宾客感受暖心。尤其是酒店自带博物馆、私家花园，地理位置相当方便，门口就是地铁站，周边环东商区，游购娱吃喝玩乐都很近。隔壁就是一家点都德，对面还有一家广州酒家。总之住花园酒店令本次旅程增色加分不少。', '2024-02-18', 5, '[''周边配套'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0202j12000d8i2lodAF8A_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0230u12000d8hpaqfC1E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000d8hln3l7442_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d8i1k4895BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000d8i2k925ADE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000d8i1zkx271D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000d8ht1aj55CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000d8hw1n2A6A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000d8hs1nsBA6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000d8hx57d565A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店还是靠谱的', '老牌酒店还是靠谱的', '2024-07-27', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230612000ewxhzdf0DCE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间挺大，有套间，室内外设计很好，环境很美，花园尤其美，有两个瀑布，很多锦鲤和花', '房间挺大，有套间，室内外设计很好，环境很美，花园尤其美，有两个瀑布，很多锦鲤和花，名副其实的花园酒店，服务还好，酒店博物馆周一闭馆', '2024-04-10', 5, '[''房间设施'', ''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235b12000dmwfn3q177C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000dmwrtp3D92E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000dmwy5ojE9D4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占据广州核心区位，后花园是最大亮点。作为中国为数不多的白金五星，办理入住居然要15分钟，完全缺少宾至如归的感觉，减分；客房比较干净，布局和配置也相对合理、精细，但是设施太老旧，白金五星居然不配智能马桶，减分；早餐种类乏善可陈，口味一般，由于场地局促，高峰时间吃饭等位严重，11点的早餐截止时间，10点30就撤摊，岂是待客之道，减分。
建议亲子度假游客，可选不含早的套餐，避免踩坑。', '2024-02-12', 3, '[''房间设施'', ''餐饮设施'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233r12000d6rnal35FA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000d6ro08z6D13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000d6rrualA8A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000d6rqncm62F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000d6rp5km2EC8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000d6rq2ol861A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000d6rp0x780C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000d6rp7ngEE3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000d6rouuvB151_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店让我有点失望！首先排队入住站着等了半小时多！不知道???什么可说的队伍一', '花园酒店让我有点失望！首先排队入住站着等了半小时多！不知道???什么可说的队伍一直没怎么动！终于排到我了吧居然居然被告知还要两小时才能有房！我的天啊我带两娃这么热的天喊我去哪里等！还说的好听给我安排景色好的高楼层！本来花园房就是21楼啊！你也没升级也没送早餐的！没什么好的体验感！
早餐也没啥特别的！就是瀑布餐厅景色不错！有花有??适合拍照??', '2024-02-18', 3, '[''退房/入住效率'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236q12000d8jc74kE96B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：设施都很新，尤其是过年入住非常有节日氛围', '设施：设施都很新，尤其是过年入住非常有节日氛围

服务：服务一般，金卡会员不能升级房型。并且可能是因为人多，让我们先去逛再来办理入住，说到时候收拾出来会给我们发短信，等了一个半小时也没有收到短信，最后去了前台说有房可以入住了，属实有点耽误时间
早餐：早餐我们在旋转餐厅吃的，环境很好，吃的也中规中矩', '2024-02-16', 4, '[''退房/入住效率'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234512000d80norz4D28_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000d80vyr4A9B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000d80os8tAA25_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000d80rmo0E06B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小来广州过年；顺手订了熟悉的花园，没想到意外惊喜，成为此行最满意的一个决定：花园酒店竟然有个大！花！园！来了这么多次都没注意过，瀑布小桥流水锦鲤，草坪鲜花，妥妥一个精致的城市园林，还不用人挤人，两娃每天都去花园里玩耍放电；来的当天是初五，大堂摆着年味集市，工作人员发金币巧克力和糖果，高跷财神合影，充满了浓浓的年味；服务也是120分，每层的电梯间都站了一位员工，迎来送往问好祝贺，亲切有礼举止专业；最最过意不去是小朋友突发肠胃炎，弄脏了床单，凌晨四点一个电话立刻来换被子和床褥，全程安慰也没有收清洁费；第二天半夜又弄脏了…依旧火速赶到换床品，住了两晚基本都在照顾小朋友生病中度过，是花园员工的温暖让我们的熬夜照料变得不那么痛苦，真的非常感动～以后来广州一定认准花园！', '2024-02-17', 5, '[''客房服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232312000d8bivk1D947_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000d8bh4a01407_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000d8bgpu9F9C2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常nice 的酒店，还会再光临。', '非常nice 的酒店，还会再光临。', '2024-07-05', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000eosx9lw8C5C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说不要尾房，结果还是给开了一间尾房，重新排队一个小时等待换房间。房间隔音很差，旁边房间的小孩吵闹都能听到，投诉多次无果，下次不会再考虑花园酒店。', '2024-02-25', 1, '[''退房/入住效率'', ''前台服务'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000dacj0eyFF07_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000dacj56z0B4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000dacik2t2226_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅和客房楼层电梯口都有迎宾接待服务，还热情地帮我们订楼下米其林餐厅的位子，从大门口开车门的服务员开始就一路给人如沐春风的感觉。
酒店地理位置很好，本身有一个小花园，有瀑布景观，对面是友谊商店，里面有广州酒家，酒店边上是点都德，去景区打车也都20分钟左右就可以。
尤其赞的是酒店里面就有三家米其林，不出酒店就可以吃到地道地美食。', '2024-02-15', 5, '[''前台服务'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000d7oly1mC307_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000d7oliahB59F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000d7okpud4004_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000d7oly1sBE87_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小，但设施齐全，床垫不错??酒店的服务态度都很好??。酒店的经典设计风格很独特，最关键的是出行方便，地铁就在旁边。来广州玩了两天，便捷的交通，舒适的入住体验还是不错滴', '2024-02-17', 5, '[''交通便利性'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000d89z21oB67E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000d89yyujD0CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000d89yw406D2A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰新老结合中西合璧，颇有岭南地区的艺术美感。瀑布餐厅也是一大特色，孩子们还可以去花园喂鱼。如果有机会还会再次入住。', '2024-02-20', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232m12000d94x8y2716E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000d94znguE6E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000d95ae71A1F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000d952pmm98E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000d95cr3vF30F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d952eq655EC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！选了桃园高端粤菜！菜品没话说，就是价格真的好贵！唯一不足，酒店卫生间设施老旧了点，淋浴房是浴缸，爬进爬出的，而且卫生间是敞开式！不太方便！隐私不够！', '2024-02-16', 4, '[''房间设施'', ''餐饮设施'', ''价格合理性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234q12000d7x7ry44B47_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000d7x9yty8FAB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000d7xcbhxFA16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000d7xjq39EED6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服务人员主动帮忙，热心。环境优雅，设施高级，卫生一直都很好。非常推荐', '2024-03-26', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000dibtxtg9F31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000dibv7k9112D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000dibvcmv9B84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000dibbainA15F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000dibghl97048_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员都态度非常非常亲切面带微笑。办理入住很顺利，看我们小孩是初中生，主动提出免费升了套房加了单人床，让我们在广州的3晚睡了舒服级了，并赠送了三套宝格丽的洗护用品套装！度过了美好的假期??', '2024-02-13', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235z12000d72nam31696_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000d72pvdy6B67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000d72n2n82114_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000d72dec44DFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000d72g5qmA1E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000d722szfB70F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000d726abp72D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000d72o31s902B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000d72q82qBB82_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂亮的瀑布，还有一个博物馆。我们一家四口，原本订的是双床房，前台小哥哥给免费升级成了粤韵大床房，然后加了一个床，房间很大，浴缸泡澡也很舒服，服务非常好也很贴心，总之就是超赞的一次入住体验！', '2024-02-19', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000d8sm2odB556_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000d8shgdm4EEE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000d8skrhhEBD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000d8saneiC3A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000d8slpor60A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000d8si5au4BD9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。套餐超值。', '2024-01-28', 5, '[''性价比'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235m12000d2ds5r3A046_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000d2drvo74719_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000d2dv38n3F6D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000d2dsnn941A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000d2dtl3qE8F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000d2e12tdA3C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000d2e1t867CBC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000d2dqc7sA4F3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000d2e12tj4D69_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的霸气奢华，活动也丰富，但是第一次来广州，光忙着在外面玩了，只最后一天吃完早餐才在酒店转了转，玩的太少，下次还会选择', '2024-05-13', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000dzc9zfo2BA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000dzcbu57B071_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000dzcacx1FB70_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春节但服务人员很充足并且态度都很好走到哪里都主动打招呼。房间电视有很多海外频道。缺点是房间硬件落后了。插座少特别是床头充电很不方便。空调温度打不上去有点冷，关了反而好点。另外床太软腰不好慎选。', '2024-02-12', 4, '[''房间设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233m12000d6t4otrDBB1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000d6t6gkd0492_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000d6sapu41DBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000d6t2kl59E0F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春节入住人较多，开了两个自助早餐的餐厅分流客人，很是贴心。每个工作人员都是微笑的跟你说新年好，很是温馨！来广州住花园，没选错！', '2024-02-12', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000d6pyj4374E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000d6pyexh80C5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞狮活动，第一次近距离接触，非常棒。酒店每个工作人员热情，礼貌，主动打招呼，不愧是老牌五星级酒店。在酒店内有不少可以打卡的地方，有着浓厚的文化氛围！', '2024-02-13', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0202512000d73hi5oC08B_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234v12000d73gu4wD24A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000d72r82vBF9C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我定的红棉大床房，下午3点办理入住时前台小哥说需要等一个多小时，可以帮我调剂到旁边楼的公寓房，有两个房间，当时我答应了。结果进去一感受，房间非常的旧，90年代装修那种感觉，旁边是长租的那种住客，环境像住居民楼，我受不了要求换到我原订的房间，告诉我还得等打扫完，于是除夕夜等到晚上快10点，终于入住了自己原先定的房间，房间装修比较新，空间也挺大的，就是没房调剂这点操作太让人迷惑了，人家总是往高了调吧，哪有他们这种往差了给我调的，幸亏坚持换回来了，不然真的得难受过年了。酒店服务员态度都挺好的，后花园的环境也很好，早餐种类也还可以，过年的氛围布置都挺用心的。', '2024-02-13', 5, '[''退房/入住效率'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b12000d6wrlhr003E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000d6wrx7d7D05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000d6ws5uq8CF8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好，工作人员热情负责，年味浓。晚上订了团年宴，因为坐在喇叭附近音响太大，跟服务员说了后，很快音量调小了，谢谢那位小姐姐负责有效率。团年宴菜量有些多，后面还有几道菜没上我们就饱了，提前走了。早餐丰盛环境好。', '2024-02-10', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231r12000d66eckq46E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000d66nloo54B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000d66nc5l55B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000d66hp7cC4BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000d669vagC2C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000d65xdfp9B46_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪最高端5星级酒店的风格，也是个独特的体验。大年三十酒店有很多特色活动非常有氛围，还赠送了几只康乃馨。这个酒店感觉外国客人挺多，还有外籍工作人员。建议：房间增加空气清新或香氛。', '2024-02-15', 4, '[''房间设施'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000d7q64wk20CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000d7q8fijDE33_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000d7pv9gb5BA6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节活动丰富 气氛浓郁 闹中取静的花园有特色', '春节活动丰富 气氛浓郁 闹中取静的花园有特色
人流特别大 有一天早餐排队太久放弃了 应该预先提醒一下客人的 酒店对满负荷运转的预备不足
房间舒适卫生 客房服务响应及时 地理位置方便
酒店餐厅运营服务水平不敢恭维
和五星级酒店的中餐厅比有较大差距
反映问题后值班经理处理及时 餐厅后续补救措施比较真诚
前台的服务人员无论是中方还是外籍的都热情周到', '2024-02-21', 4, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234f12000d9abo64764A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000d9a9bxqC57F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000d9a49clF5F7_R_150_150_R5_Q70_D.jpg\" ]"]');